import{_ as p,c as s,o as t,U as o}from"./chunks/framework.9QHaLlVJ.js";const y=JSON.parse('{"title":"缓存一致性","description":null,"frontmatter":{"lang":"zh-CN","title":"缓存一致性","description":null},"headers":[],"relativePath":"doc/架构/缓存一致性/mysql与redis/Mysql与Redis缓存一致性.md","filePath":"packages/doc/src/架构/缓存一致性/mysql与redis/Mysql与Redis缓存一致性.md","lastUpdated":1702458087000}'),r={name:"doc/架构/缓存一致性/mysql与redis/Mysql与Redis缓存一致性.md"},e=o('<p><strong>背景</strong></p><p>缓存是软件开发中一个非常有用的概念，数据库缓存更是在项目中必然会遇到的场景。而缓存一致性的保证，更是在面试中被反复问到，这里进行一下总结，针对不同的要求，选择恰到好处的一致性方案。</p><p><strong>缓存是什么</strong></p><p>存储的速度是有区别的。缓存就是把低速存储的结果，临时保存在高速存储的技术。</p><p>​ <img src="https://note.youdao.com/yws/public/resource/88fe6b787f0cd9ce543951579b48428b/xmlnote/200E73C7E3AD443E9FEE415074EB314C/31179" alt="0"></p><p>如图所示，金字塔更上面的存储，可以作为下面存储的缓存。</p><p>我们本次的讨论，主要针对数据库缓存场景，将以redis作为mysql的缓存为案例来进行。</p><p><strong>为什么需要缓存</strong></p><p>存储如mysql通常支持完整的ACID特性，因为可靠性，持久性等因素，性能普遍不高，高并发的查询会给mysql带来压力，造成数据库系统的不稳定。同时也容易产生延迟。</p><p>根据局部性原理，80%请求会落到20%的热点数据上，在读多写少场景，增加一层缓存非常有助提升系统吞吐量和健壮性。</p><p><strong>存在问题</strong></p><p>存储的数据随着时间可能会发生变化，而缓存中的数据就会不一致。具体能容忍的不一致时间，需要具体业务具体分析，但是通常的业务，都需要做到最终一致。</p><p><strong>redis作为mysql缓存</strong></p><p>通常的开发模式中，都会使用mysql作为存储，而redis作为缓存，加速和保护mysql。但是，当mysql数据更新之后，redis怎么保持同步呢。</p><p>强一致性同步成本太高，如果追求强一致，那么没必要用缓存了，直接用mysql即可。通常考虑的，都是最终一致性。</p><p>解决方案</p><p><strong>方案一</strong></p><p>通过key的过期时间，mysql更新时，redis不更新。</p><p>这种方式实现简单，但不一致的时间会很长。如果读请求非常频繁，且过期时间比较长，则会产生很多长期的脏数据。</p><p><strong>优点：</strong></p><p>开发成本低，易于实现；</p><p>管理成本低，出问题的概率会比较小。</p><p><strong>不足：</strong></p><p>完全依赖过期时间，时间太短容易缓存频繁失效，太长容易有长时间更新延迟（不一致）</p><p><strong>方案二</strong></p><p>在方案一的基础上扩展，通过key的过期时间兜底，并且，在更新mysql时，同时更新redis。</p><p>​ <img src="https://note.youdao.com/yws/public/resource/88fe6b787f0cd9ce543951579b48428b/xmlnote/3E6984820A69481CBC7717C085056295/31177" alt="0"></p><p><strong>优点：</strong></p><p>相对方案一，更新延迟更小。</p><p><strong>不足：</strong></p><p>如果更新mysql成功，更新redis却失败，就退化到了方案一；</p><p>在高并发场景，业务server需要和mysql,redis同时进行连接。这样是损耗双倍的连接资源，容易造成连接数过多的问题。</p><p><strong>方案三</strong></p><p>针对方案二的同步写redis进行优化，增加消息队列，将redis更新操作交给kafka，由消息队列保证可靠性，再搭建一个消费服务，来异步更新redis。</p><p>​ <img src="https://note.youdao.com/yws/public/resource/88fe6b787f0cd9ce543951579b48428b/xmlnote/14461CD6D2E742718EBEEF2EB51DD804/31176" alt="0"></p><p><strong>优点：</strong></p><p>消息队列可以用一个句柄，很多消息队列客户端还支持本地缓存发送，有效解决了方案二连接数过多的问题；</p><p>使用消息队列，实现了逻辑上的解耦；</p><p>消息队列本身具有可靠性，通过手动提交等手段，可以至少一次消费到redis。</p><p><strong>不足：</strong></p><p>依旧解决不了时序性问题，如果多台业务服务器分别处理针对同一行数据的两条请求，举个栗子，a = 1；a = 5; 如果mysql中是第一条先执行，而进入kafka的顺序是第二条先执行，那么数据就会产生不一致。</p><p>引入了消息队列，同时要增加服务消费消息，成本较高，还有重复消费的风险。</p><p><strong>方案四</strong></p><p>通过订阅binlog来更新redis，把我们搭建的消费服务，作为mysql的一个slave，订阅binlog，解析出更新内容，再更新到redis。</p><p>​ <img src="https://note.youdao.com/yws/public/resource/88fe6b787f0cd9ce543951579b48428b/xmlnote/541499579A214D0C93976DD0CDD55154/31178" alt="0"></p><p><strong>优点：</strong></p><p>在mysql压力不大情况下，延迟较低；</p><p>和业务完全解耦；</p><p>解决了时序性问题。</p><p><strong>缺点：</strong></p><p>要单独搭建一个同步服务，并且引入binlog同步机制，成本较大。</p><p><strong>总结</strong></p><p><strong>方案选型</strong></p><p>首先确认产品上对延迟性的要求，如果要求极高，且数据有可能变化，别用缓存。</p><p>通常来说，方案1就够了，笔者咨询过4，5个团队，基本都是用方案1，因为能用缓存方案，通常是读多写少场景，同时业务上对延迟具有一定的包容性。方案1没有开发成本，其实比较实用。</p><p>如果想增加更新时的即时性，就选择方案2，不过没必要做重试保证之类的。</p><p>方案3，方案4针对于对延时要求比较高业务，一个是推模式，一个是拉模式，而方案4具备更强的可靠性，既然都愿意花功夫做处理消息的逻辑，不如一步到位，用方案4。</p><p><strong>结论</strong></p><p>一般情况，方案1够用。若延时要求高，直接选择方案4。如果是面试场景，从简单讲到复杂，面试官会一步一步追问，咱们就一点点推导，宾主尽欢。</p>',59),n=[e];function l(g,c,d,i,a,m){return t(),s("div",null,n)}const q=p(r,[["render",l]]);export{y as __pageData,q as default};
